SELECT COUNT(*) as confirmed_sale_orders
FROM sale_order_template
WHERE active = true;

WITH
  q_finance AS (
    SELECT SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_account AS aa ON aa.id = aml.account_id JOIN account_move AS am ON am.id = aml.move_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE)
  ),
  q_demand AS (
    SELECT rp.name AS customer, COUNT(so.id) AS order_count FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY rp.name ORDER BY order_count DESC
  )
SELECT q_finance.total_revenue, q_demand.customer, q_demand.order_count
FROM q_finance CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pp.id, pt.name ->> 'en_US' AS product, COALESCE(SUM(sq.quantity), 0) AS on_hand_quantity FROM product_product AS pp JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_quant AS sq ON sq.product_id = pp.id LEFT JOIN stock_location AS sl ON sl.id = sq.location_id WHERE sl.usage = 'internal' OR sl.id IS NULL GROUP BY pp.id, pt.name ORDER BY pt.name ->> 'en_US'
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, SUM(sol.product_uom_qty) AS total_units_sold FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY pt.name ORDER BY total_units_sold DESC
  )
SELECT q_inventory.id, q_inventory.product, q_inventory.on_hand_quantity, q_demand.product AS q_demand_product, q_demand.total_units_sold
FROM q_inventory CROSS JOIN q_demand;

SELECT COUNT(so.id) AS sales_orders_created
FROM sale_order so
WHERE so.create_date >= DATE '2026-06-01' AND so.create_date < DATE '2026-07-01';

WITH
  q_inventory AS (
    SELECT pp.id, pt.name ->> 'en_US' AS product, pt.default_code AS internal_reference, COALESCE(SUM(sq.quantity), 0) AS on_hand_quantity FROM product_product AS pp JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_quant AS sq ON sq.product_id = pp.id GROUP BY pp.id, pt.name, pt.default_code ORDER BY pt.name
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, CAST(DATE_TRUNC('MONTH', so.date_order) AS DATE) AS month, SUM(sol.product_uom_qty) AS monthly_demand, AVG(SUM(sol.product_uom_qty)) OVER (PARTITION BY sol.product_id) AS avg_monthly_demand FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') GROUP BY pt.name, DATE_TRUNC('MONTH', so.date_order), sol.product_id ORDER BY pt.name, month
  )
SELECT q_inventory.id, q_inventory.product, q_inventory.internal_reference, q_inventory.on_hand_quantity, q_demand.product AS q_demand_product, q_demand.month, q_demand.monthly_demand, q_demand.avg_monthly_demand
FROM q_inventory CROSS JOIN q_demand;

WITH
  q_logistics AS (
    SELECT rp.name AS supplier, AVG(EXTRACT(EPOCH FROM (po.date_approve - po.create_date)) / 86400) AS avg_delivery_time_days, MIN(EXTRACT(EPOCH FROM (po.date_approve - po.create_date)) / 86400) AS min_delivery_time_days, MAX(EXTRACT(EPOCH FROM (po.date_approve - po.create_date)) / 86400) AS max_delivery_time_days, COUNT(po.id) AS total_orders FROM purchase_order AS po JOIN res_partner AS rp ON rp.id = po.partner_id WHERE po.state IN ('purchase', 'done') AND NOT po.date_approve IS NULL GROUP BY rp.name ORDER BY avg_delivery_time_days DESC
  ),
  q_demand AS (
    SELECT DISTINCT pt.name ->> 'en_US' AS product, psi.partner_id, rp.name AS supplier, psi.delay AS delivery_time_days FROM product_supplierinfo AS psi JOIN product_template AS pt ON pt.id = psi.product_tmpl_id JOIN res_partner AS rp ON rp.id = psi.partner_id WHERE psi.delay = (SELECT MAX(delay) FROM product_supplierinfo) ORDER BY psi.delay DESC, pt.name
  )
SELECT q_logistics.supplier, q_logistics.avg_delivery_time_days, q_logistics.min_delivery_time_days, q_logistics.max_delivery_time_days, q_logistics.total_orders, q_demand.product, q_demand.partner_id, q_demand.supplier AS q_demand_supplier, q_demand.delivery_time_days
FROM q_logistics CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pt.name ->> 'en_US' AS product, pp.id, COALESCE(SUM(svl.quantity), 0) AS total_quantity, COALESCE(SUM(svl.value), 0) AS total_value, CASE WHEN COALESCE(AVG(sq.quantity), 0) > 0 THEN COALESCE(SUM(svl.value), 0) / NULLIF(COALESCE(AVG(sq.quantity), 0), 0) ELSE 0 END AS inventory_turnover_rate FROM stock_valuation_layer AS svl JOIN stock_move AS sm ON sm.id = svl.stock_move_id JOIN product_product AS pp ON pp.id = sm.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_quant AS sq ON sq.product_id = pp.id GROUP BY pt.name, pp.id ORDER BY inventory_turnover_rate DESC
  ),
  q_finance AS (
    SELECT pt.name, SUM(aml.credit - aml.debit) AS revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN product_product AS pp ON pp.id = aml.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE aa.account_type = 'income' AND am.state = 'posted' GROUP BY pt.name ORDER BY revenue DESC
  )
SELECT q_inventory.product, q_inventory.id, q_inventory.total_quantity, q_inventory.total_value, q_inventory.inventory_turnover_rate, q_finance.name, q_finance.revenue
FROM q_inventory CROSS JOIN q_finance;

WITH
  q_finance AS (
    SELECT rp.name AS customer, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN res_partner AS rp ON rp.id = aml.partner_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) GROUP BY rp.name ORDER BY total_revenue DESC
  ),
  q_demand AS (
    SELECT rp.name AS customer, COUNT(so.id) AS order_count, SUM(so.amount_total) AS total_sales FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY rp.id, rp.name ORDER BY total_sales DESC
  )
SELECT q_finance.customer, q_finance.total_revenue, q_demand.customer AS q_demand_customer, q_demand.order_count, q_demand.total_sales
FROM q_finance CROSS JOIN q_demand;

WITH
  q_finance AS (
    SELECT rp.name AS customer, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN res_partner AS rp ON rp.id = am.partner_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= DATE_TRUNC('YEAR', CURRENT_TIMESTAMP) GROUP BY rp.name ORDER BY total_revenue DESC LIMIT 5
  ),
  q_demand AS (
    SELECT rp.name AS customer, SUM(so.amount_total) AS total_revenue FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') AND so.date_order >= DATE_TRUNC('YEAR', CURRENT_TIMESTAMP) GROUP BY rp.name ORDER BY total_revenue DESC LIMIT 5
  )
SELECT q_finance.customer, q_finance.total_revenue, q_demand.customer AS q_demand_customer, q_demand.total_revenue AS q_demand_total_revenue
FROM q_finance CROSS JOIN q_demand;

WITH
  q_finance AS (
    SELECT pt.name AS product, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN product_product AS pp ON pp.id = aml.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) GROUP BY pt.name ORDER BY total_revenue DESC
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, SUM(sol.product_uom_qty) AS units_sold, SUM(sol.price_unit * sol.product_uom_qty) AS total_sales, AVG(sol.price_unit) AS avg_unit_price FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) GROUP BY pt.name ORDER BY total_sales DESC
  )
SELECT q_finance.product, q_finance.total_revenue, q_demand.product AS q_demand_product, q_demand.units_sold, q_demand.total_sales, q_demand.avg_unit_price
FROM q_finance CROSS JOIN q_demand;

SELECT COUNT(*) as active_product_count
FROM product_template
WHERE active = true;

SELECT COUNT(*) as waiting_stock_moves
FROM stock_move_line
WHERE state = 'waiting';

WITH
  q_finance AS (
    SELECT pt.name AS product, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN product_template AS pt ON pt.id = aml.product_id WHERE aa.account_type = 'income' AND am.state = 'posted' AND am.date >= CAST('2026-05-12' AS DATE) AND am.date < CAST('2026-06-12' AS DATE) GROUP BY pt.name ORDER BY total_revenue DESC
  ),
  q_demand AS (
    SELECT pt.name ->> 'en_US' AS product, SUM(sol.product_uom_qty) AS units_sold, SUM(so.amount_total) AS total_sales FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id JOIN product_product AS pp ON pp.id = sol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-05-12' AS DATE) AND so.date_order < CAST('2026-06-12' AS DATE) GROUP BY pt.name ORDER BY total_sales DESC
  )
SELECT q_finance.product, q_finance.total_revenue, q_demand.product AS q_demand_product, q_demand.units_sold, q_demand.total_sales
FROM q_finance CROSS JOIN q_demand;

WITH
  q_inventory AS (
    SELECT pt.name ->> 'en_US' AS product, pp.id, COALESCE(SUM(sq.quantity), 0) AS current_stock FROM stock_move AS sm JOIN product_product AS pp ON pp.id = sm.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_quant AS sq ON sq.product_id = pp.id WHERE sm.date >= CAST('2026-06-01' AS DATE) AND sm.date < CAST('2026-07-01' AS DATE) GROUP BY pt.name, pp.id ORDER BY pt.name
  ),
  q_demand AS (
    SELECT so.id, so.name, so.date_order, rp.name AS customer, so.amount_total, so.state FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.date_order >= CAST('2026-06-01' AS DATE) AND so.date_order < CAST('2026-07-01' AS DATE) ORDER BY so.date_order DESC
  )
SELECT q_inventory.product, q_inventory.id, q_inventory.current_stock, q_demand.id AS q_demand_id, q_demand.name, q_demand.date_order, q_demand.customer, q_demand.amount_total, q_demand.state
FROM q_inventory CROSS JOIN q_demand;

WITH
  q_logistics AS (
    SELECT SUM(po.amount_total) AS total_confirmed_purchase_value FROM purchase_order AS po WHERE po.state IN ('purchase', 'done') AND po.date_order >= CAST('2026-01-01' AS DATE) AND po.date_order < CAST('2027-01-01' AS DATE)
  ),
  q_finance AS (
    SELECT SUM(am.amount_total_signed) AS total_paid_supplier_invoices FROM account_move AS am WHERE am.move_type = 'in_invoice' AND am.payment_state = 'paid' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE)
  )
SELECT q_logistics.total_confirmed_purchase_value, q_finance.total_paid_supplier_invoices
FROM q_logistics CROSS JOIN q_finance;

WITH
  q_demand AS (
    SELECT pt.id, pt.name ->> 'en_US' AS product_name FROM product_template AS pt WHERE NOT EXISTS(SELECT 1 FROM sale_order_line AS sol JOIN product_product AS pp ON pp.id = sol.product_id WHERE pp.product_tmpl_id = pt.id)
  ),
  q_inventory AS (
    SELECT pp.id, pt.name ->> 'en_US' AS product, COALESCE(SUM(sq.quantity), 0) AS on_hand FROM product_product AS pp JOIN product_template AS pt ON pt.id = pp.product_tmpl_id LEFT JOIN stock_quant AS sq ON sq.product_id = pp.id WHERE NOT pp.id IN (SELECT DISTINCT sm.product_id FROM stock_move AS sm JOIN stock_location AS ldst ON ldst.id = sm.location_dest_id WHERE ldst.usage = 'customer' AND sm.state = 'done') GROUP BY pp.id, pt.name ORDER BY pp.id
  )
SELECT q_demand.id, q_demand.product_name, q_inventory.id AS q_inventory_id, q_inventory.product, q_inventory.on_hand
FROM q_demand CROSS JOIN q_inventory;

WITH
  q_logistics AS (
    SELECT CAST(DATE_TRUNC('MONTH', po.date_order) AS DATE) AS month, COUNT(po.id) AS total_purchase_orders, SUM(po.amount_total) AS total_value FROM purchase_order AS po WHERE po.date_order >= CAST('2026-01-01' AS DATE) AND po.date_order < CAST('2027-01-01' AS DATE) GROUP BY DATE_TRUNC('MONTH', po.date_order) ORDER BY month
  ),
  q_finance AS (
    SELECT CAST(DATE_TRUNC('MONTH', am.date) AS DATE) AS month, SUM(aml.debit - aml.credit) AS total_spend FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id WHERE am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) AND aa.account_type LIKE 'expense%' GROUP BY DATE_TRUNC('MONTH', am.date) ORDER BY month
  )
SELECT q_logistics.month, q_logistics.total_purchase_orders, q_logistics.total_value, q_finance.month AS q_finance_month, q_finance.total_spend
FROM q_logistics CROSS JOIN q_finance;

WITH
  q_logistics AS (
    SELECT pt.name, SUM(pol.product_qty) AS incoming_volume FROM purchase_order_line AS pol JOIN purchase_order AS po ON po.id = pol.order_id JOIN product_product AS pp ON pp.id = pol.product_id JOIN product_template AS pt ON pt.id = pp.product_tmpl_id WHERE po.state IN ('purchase', 'done') AND po.date_order >= CAST('2026-01-01' AS DATE) AND po.date_order < CAST('2027-01-01' AS DATE) GROUP BY pt.name ORDER BY incoming_volume DESC
  ),
  q_demand AS (
    SELECT SUM(sol.product_uom_qty) AS outgoing_sale_volume FROM sale_order_line AS sol JOIN sale_order AS so ON so.id = sol.order_id WHERE so.state IN ('sale', 'done') AND so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE)
  )
SELECT q_logistics.name, q_logistics.incoming_volume, q_demand.outgoing_sale_volume
FROM q_logistics CROSS JOIN q_demand;

WITH
  q_demand AS (
    SELECT so.id, so.name, rp.name AS customer, so.date_order, so.amount_total, so.state, COUNT(sol.id) AS line_count, SUM(sol.product_uom_qty) AS total_qty FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id LEFT JOIN sale_order_line AS sol ON sol.order_id = so.id WHERE so.date_order >= CAST('2026-01-01' AS DATE) AND so.date_order < CAST('2027-01-01' AS DATE) AND so.state IN ('sale', 'done') GROUP BY so.id, so.name, rp.name, so.date_order, so.amount_total, so.state ORDER BY so.date_order DESC
  ),
  q_finance AS (
    SELECT rp.name AS customer, am.name AS invoice, am.amount_total AS invoice_amount, COALESCE(SUM(ap.amount), 0) AS paid_amount FROM account_move AS am JOIN res_partner AS rp ON rp.id = am.partner_id LEFT JOIN account_payment AS ap ON ap.move_id = am.id WHERE am.move_type = 'out_invoice' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) GROUP BY rp.name, am.name, am.amount_total ORDER BY rp.name, am.name
  )
SELECT q_demand.id, q_demand.name, q_demand.customer, q_demand.date_order, q_demand.amount_total, q_demand.state, q_demand.line_count, q_demand.total_qty, q_finance.customer AS q_finance_customer, q_finance.invoice, q_finance.invoice_amount, q_finance.paid_amount
FROM q_demand CROSS JOIN q_finance;

WITH
  q_logistics AS (
    SELECT rp.name AS supplier, COUNT(po.id) AS orders_placed FROM purchase_order AS po JOIN res_partner AS rp ON rp.id = po.partner_id WHERE po.date_order >= CAST('2026-01-01' AS DATE) AND po.date_order < CAST('2027-01-01' AS DATE) GROUP BY rp.name ORDER BY orders_placed DESC
  ),
  q_finance AS (
    SELECT rp.name AS supplier, SUM(aml.debit) AS total_spend, COUNT(DISTINCT am.id) AS order_count, SUM(aml.debit) / NULLIF(COUNT(DISTINCT am.id), 0) AS spend_per_order FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN res_partner AS rp ON rp.id = am.partner_id JOIN account_account AS aa ON aa.id = aml.account_id WHERE am.move_type = 'in_invoice' AND am.state = 'posted' AND am.date >= CAST('2026-01-01' AS DATE) AND am.date < CAST('2027-01-01' AS DATE) AND aa.account_type IN ('expense', 'asset') GROUP BY rp.name HAVING SUM(aml.debit) > (SELECT AVG(total) FROM (SELECT SUM(aml2.debit) AS total FROM account_move_line AS aml2 JOIN account_move AS am2 ON am2.id = aml2.move_id WHERE am2.move_type = 'in_invoice' AND am2.state = 'posted' AND am2.date >= CAST('2026-01-01' AS DATE) AND am2.date < CAST('2027-01-01' AS DATE) GROUP BY am2.partner_id) AS t) AND COUNT(DISTINCT am.id) < (SELECT AVG(cnt) FROM (SELECT COUNT(DISTINCT id) AS cnt FROM account_move WHERE move_type = 'in_invoice' AND state = 'posted' AND date >= CAST('2026-01-01' AS DATE) AND date < CAST('2027-01-01' AS DATE) GROUP BY partner_id) AS t) ORDER BY total_spend DESC, order_count ASC
  )
SELECT q_logistics.supplier, q_logistics.orders_placed, q_finance.supplier AS q_finance_supplier, q_finance.total_spend, q_finance.order_count, q_finance.spend_per_order
FROM q_logistics CROSS JOIN q_finance;

SELECT uc.id, uc.name
FROM uom_category uc
WHERE (
  SELECT COUNT(*)
  FROM product_product pp
  WHERE pp.uom_id IN (
    SELECT id FROM uom_uom WHERE category_id = uc.id
  )
) >= 5;

WITH
  q_finance AS (
    SELECT rp.name AS customer, SUM(aml.credit - aml.debit) AS total_revenue FROM account_move_line AS aml JOIN account_move AS am ON am.id = aml.move_id JOIN account_account AS aa ON aa.id = aml.account_id JOIN res_partner AS rp ON rp.id = am.partner_id WHERE aa.account_type = 'income' AND am.state = 'posted' GROUP BY rp.name ORDER BY total_revenue DESC
  ),
  q_demand AS (
    SELECT rp.name AS customer, COUNT(so.id) AS order_count, SUM(so.amount_total) AS total_sales FROM sale_order AS so JOIN res_partner AS rp ON rp.id = so.partner_id WHERE so.state IN ('sale', 'done') GROUP BY rp.id, rp.name ORDER BY total_sales DESC
  )
SELECT q_finance.customer, q_finance.total_revenue, q_demand.customer AS q_demand_customer, q_demand.order_count, q_demand.total_sales
FROM q_finance CROSS JOIN q_demand;
